const raw = $input.first().json;
const token = String(
  raw.telegram_bot_token || raw.body?.telegram_bot_token
  || $env.TELEGRAM_BOT_TOKEN || ''
).trim();
const allowedChatId = String($env.TELEGRAM_CHAT_ID || '').trim();
const qdrantUrl = String($env.QDRANT_URL || '').trim().replace(/\/$/, '');

function skip(reason) {
  return [{ json: { telegram_skip: true, channel: 'telegram', skip_reason: reason } }];
}

function reply(text, chatId) {
  return [{
    json: {
      action: 'telegram_reply',
      channel: 'telegram',
      notify_telegram: true,
      notify_email: false,
      telegram_bot_token: token,
      telegram_chat_id: chatId,
      telegram_text: text,
    },
  }];
}

let update = raw;
if (raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body)) {
  if (raw.body.update_id != null || raw.body.message) update = raw.body;
}
if (typeof raw.body === 'string' && raw.body.trim()) {
  try {
    const parsed = JSON.parse(raw.body);
    if (parsed && (parsed.update_id != null || parsed.message)) update = parsed;
  } catch (e) { /* ignore */ }
}

const msg = update?.message;
if (!msg) return skip('no_message');
if (msg.from?.is_bot) return skip('bot_message');

const chatId = String(msg.chat?.id || '').trim();
if (!token) return skip('missing_bot_token');
if (!chatId) return skip('missing_chat_id');

if (allowedChatId && chatId !== allowedChatId) {
  return reply('This bot is restricted to an authorized chat.', chatId);
}

const text = String(msg.text || '').trim();
if (!text) {
  return reply('Send me a question in plain text — I\'ll search your learning materials and reply here.', chatId);
}

function normalizeGreeting(text) {
  return String(text || '').trim().toLowerCase().replace(/[!?.…,]+$/g, '').replace(/\s+/g, ' ');
}

function isGreeting(text) {
  const t = normalizeGreeting(text);
  if (!t) return false;
  const greetings = new Set([
    'hi', 'hello', 'hey', 'hiya', 'howdy', 'greetings', 'sup', 'yo',
    'good morning', 'good afternoon', 'good evening', 'good day',
    'morning', 'afternoon', 'evening',
    'hi there', 'hello there', 'hey there',
  ]);
  if (greetings.has(t)) return true;
  return /^h+i+$/.test(t)
    || /^he+l+o+$/.test(t)
    || /^he+y+$/.test(t)
    || /^(hi|hello|hey|hola)(\s+there)?$/.test(t)
    || /^good\s+(morning|afternoon|evening|day)$/.test(t);
}

function vgiSkillUniverseGreeting() {
  const custom = String($env.TELEGRAM_RAG_WELCOME || '').trim();
  if (custom) return custom.replace(/\\n/g, '\n');
  const brand = String($env.BRAND_NAME || 'VGI Skill Universe!').trim().toUpperCase();
  return [
    'Welcome to ' + brand,
    '',
    '🤖 Ask me anything from your learning materials!',
    '',
    'I can answer questions using PDFs, tutorials, documents, and Google Drive content.',
    '',
    'Examples:',
    '• What are the key points in this PDF?',
    '• Explain this concept in simple terms.',
    '• Create a summary of this document.',
    '• What does this section mean?',
    '• Generate interview questions from this material.',
    '• Compare the topics covered in these documents.',
    '',
    '💬 Send your question to get started.',
  ].join('\n');
}

const lower = text.toLowerCase();
if (lower === '/start' || lower === '/help' || isGreeting(text)) {
  return reply(vgiSkillUniverseGreeting(), chatId);
}

function isDriveUrl(text) {
  const t = String(text || '').trim();
  return /drive\.google\.com\/(drive\/folders\/|file\/d\/)/i.test(t)
    || /^\/drive(?:@\w+)?\b/i.test(t);
}

// Drive folder/file links are handled by the Drive Q&A bot — never run a KB query on the URL text
if (isDriveUrl(text)) {
  return skip('drive_url');
}

// Bare /ask or /rag with no question — prompt instead of querying the KB
if (/^\/(?:ask|rag)(?:@\w+)?\s*$/i.test(text)) {
  return reply(
    'Send your question after /ask.\n\nExample: /ask Why is React fast?\n\nOr type your question directly without /ask.',
    chatId
  );
}

const driveRagToken = String($env.TELEGRAM_BOT_TOKEN_DRIVE_RAG || '').trim();
const isDriveBot = Boolean(driveRagToken && token === driveRagToken);

// Drive Q&A bot: always scope queries to this user's ingested Drive documents
if (isDriveBot) {
  return [{
    json: {
      action: 'query',
      channel: 'drive_rag',
      question: text,
      user_id: chatId,
      filter_results_by_user_id: true,
      kb_only: true,
      enable_fallback: false,
      enable_query_history: false,
      notify_telegram: true,
      notify_email: false,
      telegram_bot_token: token,
      telegram_chat_id: chatId,
      metadata: { drive_rag: true, telegram_chat_id: chatId, source: 'user_drive' },
      collection_name: 'knowledge_base',
      rag_score_threshold: 0.10,
      top_k: 8,
      openrouter_model: String($env.OPENROUTER_MODEL || '').trim(),
      openrouter_api_key: String($env.OPENROUTER_API_KEY || '').trim().replace(/^Bearer\s+/i, ''),
      openai_api_key: String($env.OPENAI_API_KEY || '').trim().replace(/^Bearer\s+/i, ''),
      qdrant_url: qdrantUrl,
    },
  }];
}

return [{
  json: {
    action: 'query',
    channel: 'telegram',
    question: text,
    kb_only: true,
    enable_fallback: false,
    enable_query_history: false,
    notify_telegram: true,
    notify_email: false,
    telegram_bot_token: token,
    telegram_chat_id: chatId,
    telegram_user_id: String(msg.from?.id || msg.from?.username || chatId),
    metadata: { telegram_user_id: String(msg.from?.id || ''), telegram_chat_id: chatId },
    collection_name: 'knowledge_base',
    rag_score_threshold: 0.15,
    openrouter_model: String($env.OPENROUTER_MODEL || '').trim(),
    openrouter_api_key: String($env.OPENROUTER_API_KEY || '').trim().replace(/^Bearer\s+/i, ''),
    qdrant_url: qdrantUrl,
  },
}];

const item = $input.first().json;
const token = String(item.telegram_bot_token || $env.TELEGRAM_BOT_TOKEN || '').trim();
const chatId = String(item.telegram_chat_id || $env.TELEGRAM_CHAT_ID || '').trim();
const text = String(item.telegram_text || '').trim();

if (!token || !chatId) {
  return [{
    json: {
      ...item,
      telegram_sent: false,
      telegram_error: 'Missing telegram_bot_token or telegram_chat_id. Set TELEGRAM_BOT_TOKEN and TELEGRAM_CHAT_ID in .env',
    },
  }];
}
if (!text) {
  return [{ json: { ...item, telegram_sent: false, telegram_error: 'Empty telegram message text' } }];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${token}/sendMessage`,
    body: { chat_id: chatId, text: text.slice(0, 4000) },
    json: true,
    timeout: 30000,
  });
  return [{ json: { ...item, telegram_sent: true, telegram_error: null } }];
} catch (err) {
  return [{
    json: {
      ...item,
      telegram_sent: false,
      telegram_error: String(err.message || err),
    },
  }];
}

const item = $input.first().json;
return [{
  json: {
    success: true,
    action: 'telegram_reply',
    channel: 'telegram',
    telegram_sent: item.telegram_sent === true,
    telegram_error: item.telegram_error || null,
    completed_at: new Date().toISOString(),
  },
}];

const raw = $input.first().json;
const out = { ...raw, channel: 'webhook' };

if (raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body)) {
  for (const [k, v] of Object.entries(raw.body)) {
    if (out[k] === undefined || out[k] === '' || out[k] === null) out[k] = v;
  }
}

// Default API keys from env when not in payload
if (!String(out.openrouter_api_key || '').trim()) {
  const envKey = String($env.OPENROUTER_API_KEY || '').trim();
  if (envKey) out.openrouter_api_key = envKey;
}
if (!String(out.qdrant_url || '').trim()) {
  const envQdrant = String($env.QDRANT_URL || '').trim();
  if (envQdrant) out.qdrant_url = envQdrant;
}

return [{ json: out }];

const input = $input.first().json;
const action = String(input.action || '').trim().toLowerCase();

if (!['ingest', 'query'].includes(action)) {
  throw new Error('Invalid action "' + (input.action || '') + '". Use "ingest" or "query".');
}

const out = { ...input, action };

if (action === 'ingest') {
  const hasText = Boolean(String(out.document_text || '').trim());
  const hasPath = Boolean(String(out.document_file_path || '').trim());
  const hasB64 = Boolean(String(out.document_base64 || '').trim());
  if (!hasText && !hasPath && !hasB64) {
    throw new Error('ingest requires document_file_path (recommended), document_text, or document_base64');
  }
}

if (action === 'query') {
  if (!String(out.question || '').trim()) {
    throw new Error('query requires question');
  }
  if (!String(out.openrouter_api_key || out.openai_api_key || $env.OPENROUTER_API_KEY || '').trim()) {
    throw new Error('query requires openrouter_api_key (or openai_api_key) for embeddings and answers');
  }
}

if (out.user_id) {
  out.metadata = { ...(out.metadata || {}), user_id: out.user_id };
}

if (out.fallback_providers && typeof out.fallback_providers === 'string') {
  try {
    out.fallback_providers = JSON.parse(out.fallback_providers);
  } catch (e) {
    out.fallback_providers = out.fallback_providers.split(',').map((s) => s.trim()).filter(Boolean);
  }
}

return [{
  json: {
    ...out,
    rag_score_threshold: Number(out.rag_score_threshold ?? 0.15),
    kb_only: out.kb_only !== false,
    enable_fallback: out.kb_only !== false ? out.enable_fallback === true : out.enable_fallback !== false,
    enable_query_history: out.kb_only !== false ? out.enable_query_history === true : out.enable_query_history !== false,
    run_id: out.run_id || `rag_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`,
    processed_at: new Date().toISOString(),
  }
}];

const item = $input.first().json;
const runId = item.run_id;
const FILES_DIR = '/files';
const KNOWLEDGE_DIR = '/files/knowledge';
let ext = 'txt';
let filename = String(item.document_filename || 'document.txt').trim();
const filePathInput = String(item.document_file_path || '').trim();

function resolveDocumentPath(inputPath, id, fileExt) {
  if (!inputPath) {
    return FILES_DIR + '/' + id + '.' + fileExt;
  }

  let path = inputPath.trim();
  if (!path.startsWith('/files/')) {
    if (path.startsWith('files/')) path = '/' + path;
    else path = KNOWLEDGE_DIR + '/' + path.replace(/^\.\/?files\/knowledge\//, '');
  }

  const base = path.split('/').pop() || '';
  if (!base || base === 'knowledge' || !base.includes('.')) {
    throw new Error(
      'document_file_path must be a file path (e.g. /files/knowledge/doc.txt), got: ' + inputPath
    );
  }

  return path;
}

if (filePathInput) {
  const base = filePathInput.split('/').pop() || 'document.txt';
  filename = base;
  ext = (base.split('.').pop() || 'txt').toLowerCase();
} else {
  ext = (filename.split('.').pop() || 'txt').toLowerCase();
}

const allowed = new Set(['txt', 'pdf', 'md', 'markdown', 'docx']);
if (ext === 'doc') {
  throw new Error('Legacy .doc files are not supported. Convert to .docx, .pdf, or .txt.');
}
if (!allowed.has(ext)) ext = 'txt';

const documentFilePath = resolveDocumentPath(filePathInput, runId, ext);

const text = String(item.document_text || '').trim();
const b64 = String(item.document_base64 || '').trim();

function sniffPdfFromBase64(raw) {
  try {
    const head = Buffer.from(String(raw || '').trim().slice(0, 32), 'base64').slice(0, 5).toString('ascii');
    return head === '%PDF-';
  } catch (e) {
    return false;
  }
}

if (b64 && ext !== 'pdf' && sniffPdfFromBase64(b64)) {
  ext = 'pdf';
  if (!filename.toLowerCase().endsWith('.pdf')) {
    filename = filename.includes('.') ? filename.replace(/\.[^.]+$/, '.pdf') : filename + '.pdf';
  }
}

let binary = null;
if (b64) {
  binary = {
    data: {
      data: b64,
      mimeType: ext === 'pdf'
        ? 'application/pdf'
        : ext === 'docx'
          ? 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
          : 'text/plain',
      fileName: filename,
    },
  };
} else if (text && !filePathInput) {
  const bytes = new TextEncoder().encode(text);
  let bin = '';
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  binary = {
    data: {
      data: btoa(bin),
      mimeType: 'text/plain',
      fileName: filename.endsWith('.txt') ? filename : `${filename}.txt`,
    },
  };
}

return [{
  json: {
    ...item,
    document_filename: filename,
    document_file_ext: ext,
    is_pdf: ext === 'pdf',
    is_docx: ext === 'docx',
    document_file_path: documentFilePath,
    skip_write: Boolean(filePathInput && !b64 && !text),
  },
  ...(binary ? { binary } : {}),
}];

const item = $input.first().json;
const text = String(item.document_text || '').trim();
if (!text) throw new Error('document_text is empty');

return [{
  json: {
    ...item,
    extracted_document_text: text,
    extraction_source: 'inline_text',
    document_id: item.document_id || `doc_${Date.now()}`,
    document_title: item.document_title || item.document_filename || 'Untitled',
  }
}];

const item = $input.first().json;
const filePath = String(item.document_file_path || '').trim();
if (!filePath) throw new Error('document_file_path is required for existing file mode');

const base = filePath.split('/').pop() || '';
if (!base || base === 'knowledge' || !base.includes('.')) {
  throw new Error(
    'document_file_path must point to a file (not a folder). Example: /files/knowledge/guide.txt'
  );
}
let normalizedPath = filePath;
if (!normalizedPath.startsWith('/files/')) {
  if (normalizedPath.startsWith('files/')) normalizedPath = '/' + normalizedPath;
  else throw new Error('document_file_path must start with /files/ or files/. Got: ' + filePath);
}

const ext = (base.split('.').pop() || 'txt').toLowerCase();

return [{
  json: {
    ...item,
    document_file_path: normalizedPath,
    document_file_ext: ext,
    is_pdf: ext === 'pdf',
    is_docx: ext === 'docx',
    document_filename: item.document_filename || base,
    used_existing_file: true,
  }
}];

const prep = $('Prepare Document File').first();
const binary = prep.binary || $input.first().binary;
if (!binary?.data) {
  throw new Error('Missing document binary after write for ' + (prep.json.document_file_path || 'unknown'));
}

return [{ json: prep.json, binary }];

let meta = {};
try {
  const existing = $('Use Existing Document File').first();
  if (existing?.json?.document_file_path) meta = { ...existing.json };
} catch (e) {}

if (!meta.document_file_path) {
  try {
    meta = { ...$('After Write With Binary').first().json };
  } catch (e) {}
}

if (!meta.document_file_path) {
  try {
    meta = { ...$('Prepare Document File').first().json };
  } catch (e) {}
}

const binary = $input.first().binary || {};
if (!binary?.data) {
  throw new Error('No binary data available for ' + (meta.document_file_path || 'document'));
}

function extFromPath(filePath) {
  const base = String(filePath || '').split('/').pop() || '';
  return (base.split('.').pop() || '').toLowerCase();
}

let ext = String(meta.document_file_ext || extFromPath(meta.document_file_path) || '').toLowerCase();
if (!ext || ext === meta.document_file_path) ext = extFromPath(meta.document_file_path);

try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length >= 5 && buf.slice(0, 5).toString('ascii') === '%PDF-') {
    ext = 'pdf';
  }
} catch (e) {}

const mime = String(binary?.data?.mimeType || binary?.mimeType || '').toLowerCase();
if (mime === 'application/pdf') ext = 'pdf';

meta.document_file_ext = ext || 'txt';
meta.is_pdf = ext === 'pdf';
meta.is_docx = ext === 'docx';

return [{ json: meta, binary }];

function cleanKey(key) {
  return String(key || '').trim().replace(/^Bearer\s+/i, '');
}

function isOpenRouterKey(key) {
  return /^sk-or-/i.test(cleanKey(key));
}

function chatCompletionsUrl(apiKey) {
  return isOpenRouterKey(apiKey)
    ? 'https://openrouter.ai/api/v1/chat/completions'
    : 'https://api.openai.com/v1/chat/completions';
}

function normalizeVisionModel(model, apiKey) {
  const m = String(model || $env.OCR_VISION_MODEL || $env.OPENAI_MODEL || 'gpt-4o-mini').trim();
  if (isOpenRouterKey(apiKey)) {
    return m.includes('/') ? m : 'openai/' + m.replace(/^openai\//, '');
  }
  return m.replace(/^openai\//, '');
}

async function getOpenRouterKey(payload) {
  const preferOpenAI = String($env.AI_PROVIDER || 'openai').toLowerCase() === 'openai';
  let apiKey = '';
  if (preferOpenAI) {
    apiKey = cleanKey(payload.openai_api_key || $env.OPENAI_API_KEY || '');
    if (apiKey && !isOpenRouterKey(apiKey)) return apiKey;
  }
  apiKey = cleanKey(payload.openrouter_api_key || payload.openai_api_key);
  if (!apiKey) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      apiKey = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!apiKey) apiKey = cleanKey($env.OPENAI_API_KEY || $env.OPENROUTER_API_KEY || '');
  if (!apiKey) throw new Error('Missing OPENAI_API_KEY for PDF image analysis.');
  return apiKey;
}

function extractEmbeddedImages(buffer, minBytes) {
  const images = [];
  const seen = new Set();

  for (let i = 0; i < buffer.length - 3; i++) {
    if (buffer[i] === 0xff && buffer[i + 1] === 0xd8 && buffer[i + 2] === 0xff) {
      let end = i + 3;
      while (end < buffer.length - 1) {
        if (buffer[end] === 0xff && buffer[end + 1] === 0xd9) {
          end += 2;
          break;
        }
        end++;
      }
      const slice = buffer.slice(i, end);
      const key = 'jpeg:' + slice.length + ':' + slice[10];
      if (slice.length >= minBytes && !seen.has(key)) {
        seen.add(key);
        images.push({ mimeType: 'image/jpeg', data: slice, label: 'jpeg_' + (images.length + 1) });
      }
      i = end;
    }
  }

  for (let i = 0; i < buffer.length - 8; i++) {
    if (
      buffer[i] === 0x89 && buffer[i + 1] === 0x50 && buffer[i + 2] === 0x4e &&
      buffer[i + 3] === 0x47 && buffer[i + 4] === 0x0d && buffer[i + 5] === 0x0a
    ) {
      let end = i + 8;
      while (end < buffer.length - 8) {
        if (
          buffer[end] === 0x49 && buffer[end + 1] === 0x45 && buffer[end + 2] === 0x4e &&
          buffer[end + 3] === 0x44 && buffer[end + 4] === 0xae && buffer[end + 5] === 0x42 &&
          buffer[end + 6] === 0x60 && buffer[end + 7] === 0x82
        ) {
          end += 8;
          break;
        }
        end++;
      }
      const slice = buffer.slice(i, end);
      const key = 'png:' + slice.length;
      if (slice.length >= minBytes && !seen.has(key)) {
        seen.add(key);
        images.push({ mimeType: 'image/png', data: slice, label: 'png_' + (images.length + 1) });
      }
      i = end;
    }
  }

  return images;
}

function parseImageAnalysis(raw) {
  const text = String(raw || '').trim();
  if (!text) return { ocr: '', visual: '', combined: '' };

  const ocrMatch = text.match(/EXTRACTED_TEXT:\s*([\s\S]*?)(?:\nVISUAL_SUMMARY:|$)/i);
  const visualMatch = text.match(/VISUAL_SUMMARY:\s*([\s\S]*)/i);
  let ocr = String(ocrMatch?.[1] || '').trim();
  if (/^none\.?$/i.test(ocr)) ocr = '';

  let visual = String(visualMatch?.[1] || '').trim();
  if (!ocr && !visual) {
    return { ocr: text, visual: '', combined: text };
  }
  const combined = [ocr, visual].filter(Boolean).join('\n\n');
  return { ocr, visual, combined };
}

async function analyzeImage(apiKey, model, image, index, total, maxTokens) {
  const b64 = image.data.toString('base64');
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: chatCompletionsUrl(apiKey),
    headers: {
      Authorization: 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
      'X-Title': 'RAG Knowledge Agent Image OCR',
    },
    body: {
      model,
      temperature: 0,
      max_tokens: maxTokens,
      messages: [{
        role: 'user',
        content: [
          {
            type: 'text',
            text: 'Analyze PDF image ' + index + '/' + total + ' for a searchable knowledge base.\n\n'
              + 'Reply in exactly this format:\n\n'
              + 'EXTRACTED_TEXT:\n'
              + '- [List EVERY piece of visible text verbatim: titles, headings, labels, captions, table cells, code, UI text, legends, axis labels, annotations, numbers. One line per item with "- " prefix.]\n'
              + '- [If there is no readable text, write "none"]\n\n'
              + 'VISUAL_SUMMARY:\n'
              + '[1-3 sentences: image type (chart/diagram/table/screenshot/photo), layout, and what the image shows. Include relationships between labeled elements.]',
          },
          {
            type: 'image_url',
            image_url: { url: 'data:' + image.mimeType + ';base64,' + b64 },
          },
        ],
      }],
    },
    json: true,
    timeout: 120000,
  });
  return parseImageAnalysis(String(response.choices?.[0]?.message?.content || '').trim());
}

const ctx = $input.first().json;
const enableImageAnalysis = ctx.enable_pdf_image_analysis !== false && ctx.enable_pdf_ocr !== false;

if (!enableImageAnalysis) {
  return [{
    json: {
      ...ctx,
      pdf_image_ocr_text: '',
      pdf_image_description_text: '',
      pdf_image_analysis_text: '',
      pdf_images_detected: 0,
      pdf_images_ocrd: 0,
      pdf_images_described: 0,
      pdf_image_analysis_failures: 0,
      pdf_image_analysis_errors: [],
      ocr_skipped: true,
    },
  }];
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const minBytes = Math.max(Number(ctx.pdf_ocr_min_image_bytes || 2048), 512);
const maxImages = Math.min(Math.max(Number(ctx.max_pdf_ocr_images || 25), 1), 50);
const maxTokens = Math.min(Math.max(Number(ctx.pdf_ocr_max_tokens || 700), 150), 1500);
const model = String(ctx.ocr_vision_model || $env.OCR_VISION_MODEL || ctx.openrouter_model || $env.OPENROUTER_MODEL || '').trim();

const images = extractEmbeddedImages(buffer, minBytes).slice(0, maxImages);
const apiKey = await getOpenRouterKey.call(this, ctx);

const ocrParts = [];
const visualParts = [];
const errors = [];
let ocrd = 0;
let described = 0;

for (let i = 0; i < images.length; i++) {
  try {
    const { ocr, visual, combined } = await analyzeImage.call(
      this, apiKey, model, images[i], i + 1, images.length, maxTokens
    );
    if (ocr) {
      ocrParts.push('[Image ' + (i + 1) + ': ' + images[i].label + ']\n' + ocr);
      ocrd++;
    }
    if (visual) {
      visualParts.push('[Image ' + (i + 1) + ': ' + images[i].label + ']\n' + visual);
    }
    if (combined) described++;
  } catch (err) {
    errors.push({
      image: images[i].label,
      error: String(err.message || err).slice(0, 200),
    });
  }
}

const imageOcrText = ocrParts.join('\n\n');
const imageDescriptionText = visualParts.join('\n\n');
const imageAnalysisText = [imageOcrText, imageDescriptionText].filter(Boolean).join('\n\n');

return [{
  json: {
    ...ctx,
    pdf_image_ocr_text: imageOcrText,
    pdf_image_description_text: imageDescriptionText,
    pdf_image_analysis_text: imageAnalysisText,
    pdf_images_detected: images.length,
    pdf_images_ocrd: ocrd,
    pdf_images_described: described,
    pdf_image_analysis_failures: errors.length,
    pdf_image_analysis_errors: errors,
    ocr_vision_model: model,
    ocr_skipped: false,
  },
}];

const ctx = $('Restore Meta After Read').first().json;

let nativeText = '';
try {
  const pdfRow = $('Extract PDF Text').first().json;
  nativeText = String(pdfRow.text || pdfRow.data || pdfRow.content || '').trim();
} catch (e) {}

let imageOcrText = '';
let imageDescriptionText = '';
let ocrMeta = {};
try {
  const ocrRow = $('OCR PDF Images').first().json;
  imageOcrText = String(ocrRow.pdf_image_ocr_text || '').trim();
  imageDescriptionText = String(ocrRow.pdf_image_description_text || '').trim();
  if (!imageOcrText && !imageDescriptionText) {
    imageOcrText = String(ocrRow.pdf_image_analysis_text || '').trim();
  }
  ocrMeta = {
    pdf_images_detected: ocrRow.pdf_images_detected ?? 0,
    pdf_images_ocrd: ocrRow.pdf_images_ocrd ?? 0,
    pdf_images_described: ocrRow.pdf_images_described ?? ocrRow.pdf_images_ocrd ?? 0,
    pdf_image_analysis_failures: ocrRow.pdf_image_analysis_failures ?? 0,
    pdf_image_analysis_errors: ocrRow.pdf_image_analysis_errors || [],
    ocr_skipped: ocrRow.ocr_skipped === true,
    ocr_vision_model: ocrRow.ocr_vision_model,
  };
} catch (e) {}

const sections = [];
if (nativeText) sections.push(nativeText);
const ocrdCount = ocrMeta.pdf_images_ocrd ?? 0;
const describedCount = ocrMeta.pdf_images_described ?? 0;
if (imageOcrText && ocrdCount > 0) {
  sections.push('--- Text extracted from embedded images (OCR) ---\n' + imageOcrText);
}
if (imageDescriptionText && describedCount > 0) {
  sections.push('--- Visual description of embedded images ---\n' + imageDescriptionText);
}

const combined = sections.join('\n\n').trim();
if (!combined) {
  throw new Error(
    'No text extracted from PDF. The file may be empty, encrypted, or use unsupported image encoding. Provide a text-based PDF or ensure openrouter_api_key is set for vision OCR.'
  );
}

return [{
  json: {
    ...ctx,
    extracted_document_text: combined,
    pdf_native_text_chars: nativeText.length,
    pdf_image_ocr_chars: imageOcrText.length,
    pdf_image_description_chars: imageDescriptionText.length,
    extraction_source: (imageOcrText || imageDescriptionText)
      ? (nativeText ? 'pdf_text_and_image_ocr' : 'pdf_image_ocr_only')
      : 'saved_pdf_file',
    analyzed_from: ctx.document_file_path,
    ...ocrMeta,
  },
}];

function extractDocxXmlText(xml) {
  const parts = [];
  const re = /<w:t[^>]*>([^<]*)<\/w:t>/g;
  let m;
  while ((m = re.exec(xml))) {
    if (m[1]) parts.push(m[1]);
  }
  return parts.join(' ').replace(/\s+/g, ' ').trim();
}

function extractDocxFromBuffer(buffer) {
  try {
    const AdmZip = require('adm-zip');
    const zip = new AdmZip(buffer);
    const entry = zip.getEntry('word/document.xml');
    if (!entry) throw new Error('word/document.xml not found in DOCX');
    const xml = entry.getData().toString('utf8');
    const text = extractDocxXmlText(xml);
    if (text) return text;
  } catch (e) {
    // fallback below
  }

  const raw = buffer.toString('binary');
  const marker = 'word/document.xml';
  const idx = raw.indexOf(marker);
  if (idx >= 0) {
    const slice = raw.slice(idx, idx + 500000);
    const text = extractDocxXmlText(slice);
    if (text) return text;
  }

  throw new Error(
    'Could not extract DOCX text. Add adm-zip to NODE_FUNCTION_ALLOW_EXTERNAL in docker-compose.yml, or convert to PDF/TXT.'
  );
}

const ctx = $('Restore Meta After Read').first().json;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const text = extractDocxFromBuffer(buffer);
if (!text) throw new Error('DOCX file produced no extractable text');

return [{
  json: {
    ...ctx,
    extracted_document_text: text,
    extraction_source: 'docx_file',
    analyzed_from: ctx.document_file_path,
  }
}];

const ctx = $('Restore Meta After Read').first().json;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const text = buffer.toString('utf8').trim();
if (!text) throw new Error('Saved TXT/MD file is empty');

return [{
  json: {
    ...ctx,
    extracted_document_text: text,
    extraction_source: 'saved_txt_file',
    analyzed_from: ctx.document_file_path,
  }
}];

const item = $input.first().json;
const text = String(item.extracted_document_text || item.document_text || '').trim();
if (!text) throw new Error('No document text available for chunking');

const chunkSize = Number(item.chunk_size || 1000);
const overlap = Number(item.chunk_overlap || 200);
const documentId = String(item.document_id || `doc_${Date.now()}`).trim();
const documentTitle = String(item.document_title || item.document_filename || 'Untitled').trim();

function normalizePdfText(content) {
  let t = String(content || '');
  t = t.replace(/([A-Za-z])- ([a-z])/g, '$1$2');
  t = t.replace(/\beval\s+uation\b/gi, 'evaluation');
  t = t.replace(
    /encompassing the retrieval of information retrieval (?:\(IR\)|IR) all manner of/gi,
    'encompassing the retrieval of all types of'
  );
  t = t.replace(/\binformation retrieval\s+IR\b/gi, 'information retrieval (IR)');
  t = t.replace(/\ball types of media of media\b/gi, 'all types of media');
  t = t.replace(/\b([a-z]{1,2})\s+queries\b/gi, 'encoding queries');
  return t;
}

function chunkText(content, size, lap) {
  const chunks = [];
  const clean = normalizePdfText(content).replace(/\s+/g, ' ').trim();
  if (!clean) return chunks;
  let start = 0;
  while (start < clean.length) {
    const end = Math.min(start + size, clean.length);
    chunks.push({
      chunk_index: chunks.length,
      text: clean.slice(start, end),
      char_start: start,
      char_end: end,
    });
    if (end >= clean.length) break;
    start = Math.max(0, end - lap);
  }
  return chunks;
}

const chunks = chunkText(text, chunkSize, overlap);
if (!chunks.length) throw new Error('Document produced zero chunks');

return [{
  json: {
    ...item,
    document_id: documentId,
    document_title: documentTitle,
    chunks,
    chunks_count: chunks.length,
    total_chars: text.length,
  }
}];

const FREE_EMBEDDING_MODEL = String($env.EMBEDDING_MODEL || 'nvidia/llama-nemotron-embed-vl-1b-v2:free').trim();

function cleanKey(key) {
  return String(key || '').trim().replace(/^Bearer\s+/i, '');
}

function isPlaceholderKey(key) {
  const k = cleanKey(key).toLowerCase();
  return !k
    || k.includes('your-key')
    || k.includes('your-openai')
    || k === 'sk-or-v1-your-key'
    || k === 'sk-your-key-here';
}

function isOpenRouterKey(key) {
  return /^sk-or-/i.test(cleanKey(key));
}

function resolveEmbeddingModel(model, useOpenRouter) {
  const m = String(model || FREE_EMBEDDING_MODEL).trim();
  if (!useOpenRouter) return m.replace(/^openai\//, '');
  if (m.includes('/')) return m;
  return `openai/${m}`;
}

function embeddingModelsToTry(requestedModel, useOpenRouter) {
  const primary = resolveEmbeddingModel(requestedModel, useOpenRouter);
  const models = [primary];
  if (primary !== FREE_EMBEDDING_MODEL && !/:free$/i.test(primary)) {
    models.push(FREE_EMBEDDING_MODEL);
  }
  return [...new Set(models)];
}

async function resolveEmbeddingAuth(payload) {
  const openaiKey = cleanKey(payload.openai_api_key || $env.OPENAI_API_KEY || '');
  const openrouterKey = cleanKey(payload.openrouter_api_key || $env.OPENROUTER_API_KEY || '');
  let credKey = '';
  try {
    const cred = await this.getCredentials('httpHeaderAuth');
    credKey = cleanKey(cred.value || cred.headerValue);
  } catch (e) {}

  const provider = String(payload.embedding_provider || $env.AI_PROVIDER || 'auto').toLowerCase();

  if (provider === 'openai') {
    const key = openaiKey && !isOpenRouterKey(openaiKey) ? openaiKey : '';
    if (!key || isPlaceholderKey(key)) {
      throw new Error('Missing valid openai_api_key for embeddings (sk-...).');
    }
    return { key, useOpenRouter: false };
  }

  if (provider === 'openrouter') {
    const key = openrouterKey || (isOpenRouterKey(credKey) ? credKey : '');
    if (!key || isPlaceholderKey(key)) {
      throw new Error('Missing valid openrouter_api_key for embeddings (sk-or-v1-...).');
    }
    return { key, useOpenRouter: true };
  }

  if (openaiKey && !isOpenRouterKey(openaiKey) && !isPlaceholderKey(openaiKey)) {
    return { key: openaiKey, useOpenRouter: false };
  }

  if (openrouterKey && !isPlaceholderKey(openrouterKey)) {
    return { key: openrouterKey, useOpenRouter: true };
  }
  if (openaiKey && isOpenRouterKey(openaiKey) && !isPlaceholderKey(openaiKey)) {
    return { key: openaiKey, useOpenRouter: true };
  }
  if (isOpenRouterKey(credKey) && !isPlaceholderKey(credKey)) {
    return { key: credKey, useOpenRouter: true };
  }
  if (credKey && !isOpenRouterKey(credKey) && !isPlaceholderKey(credKey)) {
    return { key: credKey, useOpenRouter: false };
  }

  throw new Error('Missing embedding API key. Pass openrouter_api_key (recommended) or openai_api_key in the request body, or attach HTTP Header Auth on embedding nodes.');
}

async function requestEmbeddings(auth, payload, model, input) {
  const { key, useOpenRouter } = auth;
  const url = useOpenRouter
    ? 'https://openrouter.ai/api/v1/embeddings'
    : 'https://api.openai.com/v1/embeddings';

  const headers = {
    Authorization: `Bearer ${key}`,
    'Content-Type': 'application/json',
  };
  if (useOpenRouter) {
    headers['HTTP-Referer'] = payload.brand_website || 'https://n8n-flow.local';
    headers['X-Title'] = 'RAG Knowledge Agent';
  }

  return this.helpers.httpRequest({
    method: 'POST',
    url,
    headers,
    body: { model, input },
    json: true,
    timeout: 120000,
  });
}

function isCreditsError(err) {
  const status = err?.statusCode || err?.response?.statusCode;
  const msg = String(err?.message || err?.description || err || '');
  return status === 402 || /402|insufficient credits|never purchased credits/i.test(msg);
}

async function createEmbeddings(payload, input) {
  const auth = await resolveEmbeddingAuth.call(this, payload);
  const models = embeddingModelsToTry(payload.embedding_model, auth.useOpenRouter);
  let lastErr = null;

  for (let i = 0; i < models.length; i++) {
    const model = models[i];
    try {
      return await requestEmbeddings.call(this, auth, payload, model, input);
    } catch (err) {
      lastErr = err;
      const status = err?.statusCode || err?.response?.statusCode;
      if (status === 401) {
        throw new Error(
          auth.useOpenRouter
            ? 'Embeddings API 401: invalid or expired openrouter_api_key. Create a key at openrouter.ai/keys and pass it as openrouter_api_key.'
            : 'Embeddings API 401: invalid openai_api_key. OpenRouter keys (sk-or-v1-...) must be sent as openrouter_api_key, not openai_api_key.'
        );
      }
      const canFallback = isCreditsError(err) && i < models.length - 1;
      if (canFallback) continue;
      if (isCreditsError(err)) {
        throw new Error('Embeddings API 402: insufficient OpenRouter credits. Using free model failed too — try again later or add credits at https://openrouter.ai/settings/credits');
      }
      throw err;
    }
  }

  throw lastErr || new Error('Embeddings request failed');
}

function fnv1a(str, seed = 0x811c9dc5) {
  let h = seed >>> 0;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return h >>> 0;
}

function pointId(documentId, chunkIndex) {
  const key = `${documentId}:${chunkIndex}`;
  const parts = [
    fnv1a(key),
    fnv1a(key, 0x9e3779b9),
    fnv1a(key, 0x85ebca6b),
    fnv1a(key, 0xc2b2ae35),
  ].map((n) => n.toString(16).padStart(8, '0'));
  const hex = parts.join('');
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
}

const item = $input.first().json;
const chunks = item.chunks || [];
const texts = chunks.map((c) => c.text);

const response = await createEmbeddings.call(this, item, texts);

const vectors = (response.data || []).map((row) => row.embedding);
if (vectors.length !== chunks.length) {
  throw new Error(`Embedding count mismatch: expected ${chunks.length}, got ${vectors.length}`);
}

const vectorSize = vectors[0]?.length || Number(item.embedding_dimensions || 2048);
const points = chunks.map((chunk, i) => ({
  id: pointId(item.document_id, chunk.chunk_index),
  vector: vectors[i],
  payload: {
    document_id: item.document_id,
    document_title: item.document_title,
    chunk_index: chunk.chunk_index,
    text: chunk.text,
    char_start: chunk.char_start,
    char_end: chunk.char_end,
    source_file: item.document_file_path || null,
    ingested_at: new Date().toISOString(),
    user_id: item.user_id || null,
    metadata: { ...(item.metadata || {}), user_id: item.user_id || null },
  },
}));

return [{
  json: {
    ...item,
    embedding_model: response.model || item.embedding_model || 'nvidia/llama-nemotron-embed-vl-1b-v2:free',
    vector_size: vectorSize,
    qdrant_points: points,
  }
}];

async function probeQdrant(url) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${url}/collections`,
      json: true,
      timeout: 5000,
    });
    return res?.status === 'ok' || Array.isArray(res?.result?.collections);
  } catch (err) {
    return false;
  }
}

async function resolveQdrantUrl(item) {
  const configured = String(item.qdrant_url || '').replace(/\/$/, '').trim();
  const envUrl = String($env.QDRANT_URL || '').replace(/\/$/, '').trim();
  const candidates = [];
  if (envUrl) candidates.push(envUrl);
  if (configured) candidates.push(configured);
  candidates.push(
    'http://qdrant:6333',
    'http://host.docker.internal:6333',
    'http://127.0.0.1:6333',
    'http://localhost:6333',
  );

  const seen = new Set();
  for (const url of candidates) {
    if (!url || seen.has(url)) continue;
    seen.add(url);
    if (await probeQdrant.call(this, url)) return url;
  }

  throw new Error(
    'Cannot reach Qdrant. Run: docker compose up -d qdrant (or docker compose up -d). Tried: ' + [...seen].join(', ')
  );
}

async function getCollectionVectorSize(qdrantUrl, collection) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${qdrantUrl}/collections/${collection}`,
      json: true,
      timeout: 10000,
    });
    const vectors = res.result?.config?.params?.vectors;
    if (typeof vectors?.size === 'number') return vectors.size;
    if (vectors && typeof vectors === 'object') {
      const first = Object.values(vectors)[0];
      if (first && typeof first.size === 'number') return first.size;
    }
  } catch (err) {
    const status = err?.statusCode || err?.response?.statusCode;
    if (status === 404) return null;
  }
  return null;
}

async function ensureCollection(qdrantUrl, collection, vectorSize) {
  const existingSize = await getCollectionVectorSize.call(this, qdrantUrl, collection);
  if (existingSize && existingSize !== vectorSize) {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: `${qdrantUrl}/collections/${collection}`,
      json: true,
      timeout: 30000,
    });
  }

  try {
    await this.helpers.httpRequest({
      method: 'PUT',
      url: `${qdrantUrl}/collections/${collection}`,
      body: { vectors: { size: vectorSize, distance: 'Cosine' } },
      json: true,
      timeout: 30000,
    });
  } catch (err) {
    const status = err?.statusCode || err?.response?.statusCode;
    const msg = String(err?.message || '');
    if (status === 409 || msg.includes('409') || msg.toLowerCase().includes('already exists')) return;
    throw err;
  }
}

async function deleteDocumentPoints(qdrantUrl, collection, documentId) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${qdrantUrl}/collections/${collection}/points/delete?wait=true`,
      body: {
        filter: {
          must: [{ key: 'document_id', match: { value: documentId } }],
        },
      },
      json: true,
      timeout: 60000,
    });
  } catch (err) {
    const status = err?.statusCode || err?.response?.statusCode;
    const msg = String(err?.message || '');
    if (status === 404 || msg.includes('404') || msg.toLowerCase().includes('not found')) return;
    throw err;
  }
}

const item = $input.first().json;
const qdrantUrl = await resolveQdrantUrl.call(this, item);
const collection = String(item.collection_name || 'knowledge_base').trim();
const vectorSize = Number(item.vector_size || item.embedding_dimensions || 2048);
