    model_used: result.model_used,
    source_used: sourceUsed,
    out_of_scope: outOfScope,
    fallback_triggered: outOfScope,
    retrieval_count: relevantHits.length,
    retrieved_chunks: relevantHits,
    external_providers: [],
    answer_branch: outOfScope ? 'no_fallback' : 'rag',
    operation_mode: outOfScope ? 'out_of_scope' : 'document_rag',
  },
}];

async function webSearch(item, question) {
  const provider = String(item.web_search_provider || 'duckduckgo').toLowerCase();
  const apiKey = String(item.web_search_api_key || '').trim();

  if (provider === 'tavily' && apiKey) {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.tavily.com/search',
      body: { api_key: apiKey, query: question, max_results: 5, include_answer: true },
      json: true,
      timeout: 30000,
    });
    const snippets = (res.results || [])
      .map((r) => (r.title ? r.title + ': ' : '') + (r.content || ''))
      .filter(Boolean)
      .join('\n');
    return { text: [res.answer, snippets].filter(Boolean).join('\n').trim(), provider: 'tavily' };
  }

  if (provider === 'brave' && apiKey) {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.search.brave.com/res/v1/web/search?q=' + encodeURIComponent(question) + '&count=5',
      headers: { 'X-Subscription-Token': apiKey, Accept: 'application/json' },
      json: true,
      timeout: 30000,
    });
    const snippets = (res.web?.results || [])
      .map((r) => (r.title || '') + ': ' + (r.description || ''))
      .join('\n');
    return { text: snippets.trim(), provider: 'brave' };
  }

  if (provider === 'serpapi' && apiKey) {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://serpapi.com/search.json?q=' + encodeURIComponent(question) + '&api_key=' + encodeURIComponent(apiKey) + '&num=5',
      json: true,
      timeout: 30000,
    });
    const snippets = (res.organic_results || [])
      .map((r) => (r.title || '') + ': ' + (r.snippet || ''))
      .join('\n');
    return { text: snippets.trim(), provider: 'serpapi' };
  }

  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.duckduckgo.com/?q=' + encodeURIComponent(question) + '&format=json&no_redirect=1',
    json: true,
    timeout: 20000,
  });
  const parts = [];
  if (res.AbstractText) parts.push(res.AbstractText);
  for (const t of (res.RelatedTopics || []).slice(0, 8)) {
    if (t.Text) parts.push(t.Text);
    else if (Array.isArray(t.Topics)) {
      for (const sub of t.Topics.slice(0, 3)) {
        if (sub.Text) parts.push(sub.Text);
      }
    }
  }
  return { text: parts.join('\n').trim(), provider: 'duckduckgo' };
}

async function fetchCustomApi(item, question) {
  const url = String(item.fallback_api_url || '').trim();
  if (!url) return null;
  const method = String(item.fallback_api_method || 'POST').toUpperCase();
  const headers = item.fallback_api_headers && typeof item.fallback_api_headers === 'object'
    ? item.fallback_api_headers
    : { 'Content-Type': 'application/json' };
  const body = item.fallback_api_body || { question, query: question };
  const res = await this.helpers.httpRequest({
    method,
    url,
    headers,
    body: method === 'GET' ? undefined : body,
    json: true,
    timeout: 30000,
  });
  const text = typeof res === 'string'
    ? res
    : String(res.context || res.answer || res.text || res.content || JSON.stringify(res)).slice(0, 12000);
  return { text, provider: 'custom_api' };
}

async function fetchNotion(item, question) {
  const token = String(item.notion_api_key || '').trim();
  const databaseId = String(item.notion_database_id || '').trim();
  if (!token || !databaseId) return null;
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/databases/' + databaseId + '/query',
    headers: {
      Authorization: 'Bearer ' + token,
      'Notion-Version': '2022-06-28',
      'Content-Type': 'application/json',
    },
    body: { page_size: 5, filter: { property: 'title', title: { contains: question.slice(0, 80) } } },
    json: true,
    timeout: 30000,
  });
  const rows = (res.results || []).map((page) => JSON.stringify(page.properties || {})).join('\n');
  return rows ? { text: rows.slice(0, 12000), provider: 'notion' } : null;
}

async function fetchConfluence(item, question) {
  const base = String(item.confluence_base_url || '').trim().replace(/\/$/, '');
  const token = String(item.confluence_api_token || '').trim();
  const email = String(item.confluence_email || '').trim();
  if (!base || !token) return null;
  const auth = email ? Buffer.from(email + ':' + token).toString('base64') : token;
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: base + '/wiki/rest/api/content/search?cql=text~' + encodeURIComponent('"' + question.slice(0, 120) + '"') + '&limit=5',
    headers: { Authorization: 'Basic ' + auth, Accept: 'application/json' },
    json: true,
    timeout: 30000,
  });
  const snippets = (res.results || [])
    .map((r) => (r.title || '') + ': ' + (r.excerpt || r.body?.storage?.value || '').replace(/<[^>]+>/g, ' ').slice(0, 500))
    .join('\n');
  return snippets.trim() ? { text: snippets.trim(), provider: 'confluence' } : null;
}

async function fetchDatabaseRecords(item, question) {
  const url = String(item.database_query_url || '').trim();
  if (!url) return null;
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: { 'Content-Type': 'application/json', ...(item.database_query_headers || {}) },
    body: { question, query: question, limit: 5 },
    json: true,
    timeout: 30000,
  });
  const text = String(res.records || res.rows || res.data || res.result || JSON.stringify(res)).slice(0, 12000);
  return text ? { text, provider: 'database' } : null;
}

const PROVIDER_FETCHERS = {
  custom_api: fetchCustomApi,
  database: fetchDatabaseRecords,
  notion: fetchNotion,
  confluence: fetchConfluence,
  web_search: webSearch,
};

function resolveProviderOrder(item) {
  const custom = item.fallback_providers;
  if (Array.isArray(custom) && custom.length) {
    return custom.map((id) => String(id).trim().toLowerCase()).filter(Boolean);
  }
  return ["custom_api","database","notion","confluence","web_search"];
}

const item = $input.first().json;
const question = String(item.question || '').trim();
const order = resolveProviderOrder(item);
const sections = [];
const providers = [];

for (const providerId of order) {
  if (providerId === 'web_search' && item.enable_web_search === false) continue;
  const fetcher = PROVIDER_FETCHERS[providerId];
  if (!fetcher) continue;
  try {
    const result = await fetcher.call(this, item, question);
    if (result?.text) {
      sections.push('[' + result.provider + ']\n' + result.text);
      providers.push(result.provider);
    }
  } catch (e) {
    // try next provider
  }
}

return [{
  json: {
    ...item,
    external_context: sections.join('\n\n---\n\n'),
    external_providers: providers,
    has_external_context: sections.length > 0,
  },
}];

function cleanKey(key) {
  return String(key || '').trim().replace(/^Bearer\s+/i, '');
}

function isPlaceholderKey(key) {
  const k = cleanKey(key).toLowerCase();
  return !k
    || k.includes('your-key')
    || k.includes('your-openai')
    || k === 'sk-or-v1-your-key'
    || k === 'sk-your-key-here';
}

function isOpenRouterKey(key) {
  return /^sk-or-/i.test(cleanKey(key));
}

function aiProviderPrefersOpenAI() {
  return String($env.AI_PROVIDER || 'openai').toLowerCase() === 'openai';
}

function chatCompletionsUrl(apiKey) {
  return isOpenRouterKey(apiKey)
    ? 'https://openrouter.ai/api/v1/chat/completions'
    : 'https://api.openai.com/v1/chat/completions';
}

function chatHeaders(apiKey, title) {
  const headers = {
    Authorization: 'Bearer ' + apiKey,
    'Content-Type': 'application/json',
  };
  if (isOpenRouterKey(apiKey) && title) headers['X-Title'] = title;
  return headers;
}

function normalizeChatModel(model, apiKey) {
  const m = String(model || $env.OPENAI_MODEL || $env.OPENROUTER_MODEL || 'gpt-4o-mini').trim();
  if (isOpenRouterKey(apiKey)) {
    return m.includes('/') ? m : 'openai/' + m.replace(/^openai\//, '');
  }
  return m.replace(/^openai\//, '');
}

async function getChatApiKey(payload) {
  const preferOpenAI = aiProviderPrefersOpenAI();
  let openaiKey = cleanKey(payload?.openai_api_key || $env.OPENAI_API_KEY || '');
  let orKey = cleanKey(payload?.openrouter_api_key || $env.OPENROUTER_API_KEY || '');

  if (preferOpenAI && openaiKey && !isPlaceholderKey(openaiKey)) {
    return { key: openaiKey, useOpenRouter: false };
  }
  if (orKey && !isPlaceholderKey(orKey) && isOpenRouterKey(orKey)) {
    return { key: orKey, useOpenRouter: true };
  }
  if (openaiKey && !isPlaceholderKey(openaiKey) && !isOpenRouterKey(openaiKey)) {
    return { key: openaiKey, useOpenRouter: false };
  }

  let credKey = '';
  try {
    const cred = await this.getCredentials('httpHeaderAuth');
    credKey = cleanKey(cred.value || cred.headerValue);
  } catch (e) {}

  if (credKey && !isPlaceholderKey(credKey)) {
    return { key: credKey, useOpenRouter: isOpenRouterKey(credKey) };
  }

  throw new Error('Missing AI API key. Set OPENAI_API_KEY in .env (recommended) or openrouter_api_key in the request body.');
}

async function getOpenRouterKey(payload) {
  const auth = await getChatApiKey.call(this, payload || {});
  return auth.key;
}

function chatModels(primary, payload) {
  const authKey = cleanKey(payload?.openai_api_key || payload?.openrouter_api_key || $env.OPENAI_API_KEY || $env.OPENROUTER_API_KEY || '');
  const models = [];
  const main = normalizeChatModel(primary || payload?.openrouter_model || $env.OPENAI_MODEL || $env.OPENROUTER_MODEL, authKey);
  if (main) models.push(main);
  const fallback = normalizeChatModel($env.OPENAI_MODEL_SPECIALIST || $env.OPENROUTER_FALLBACK_MODEL || 'gpt-4o-mini', authKey);
  if (fallback && !models.includes(fallback)) models.push(fallback);
  if (!models.length) models.push(normalizeChatModel('gpt-4o-mini', authKey));
  return [...new Set(models)];
}

async function chatCompletionOnce(apiKey, model, systemPrompt, userPrompt, temperature) {
  const normalizedModel = normalizeChatModel(model, apiKey);
  let response;
  try {
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: chatCompletionsUrl(apiKey),
      headers: chatHeaders(apiKey, 'RAG Knowledge Agent'),
      body: {
        model: normalizedModel,
        temperature: temperature ?? 0.2,
        max_tokens: 700,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      },
      json: true,
      timeout: 90000,
      ignoreHttpStatusErrors: true,
    });
  } catch (err) {
    const wrapped = new Error(err.message || 'AI chat completion failed.');
    wrapped.statusCode = Number(err.statusCode || err.httpCode || 500);
    throw wrapped;
  }

  if (response?.error) {
    const err = new Error(response.error.message || 'AI chat completion failed.');
    err.statusCode = Number(response.error.code || 500);
    throw err;
  }

  const answer = response.choices?.[0]?.message?.content?.trim();
  if (!answer) throw new Error('AI returned an empty answer.');
  return {
    answer,
    model_used: response.model || normalizedModel,
  };
}

async function chatCompletion(apiKey, model, systemPrompt, userPrompt, temperature, payload) {
  const models = chatModels(model, payload || {});
  let lastErr;
  for (const candidate of models) {
    try {
      return await chatCompletionOnce.call(this, apiKey, candidate, systemPrompt, userPrompt, temperature);
    } catch (err) {
      lastErr = err;
      const code = Number(err.statusCode || err.httpCode || 0);
      if (code === 402 || code === 429 || code >= 500) continue;
      throw err;
    }
  }
  throw lastErr || new Error('AI chat completion failed.');
}

